mapper.select:
      
      SELECT * FROM (
         SELECT ROWNUM AS RNUM, list.* FROM (
            SELECT * FROM bnc_notice notice 
      
	      
	         
	         WHERE notice.${searchType} like '%'||#{searchKeyword}||'%'
	         
	      
      
         ) list
      )
      
      
      
      WHERE RNUM > #{startRowNumber} AND RNUM <= #{endRowNumber}
      order by notc_number desc
